#include <bits/stdc++.h>
using namespace std;
int gys(int a,int b){
	while(a%b!=0){
		int c=a%b;
		a=b;
		b=c;
	}
	return b;
}
int main(){
	int n;
	cin>>n;
	int b[15];
	for(int i=0;i<n;i++){
		cin>>b[i];
	}
	long long cnt=b[0];
	for(int i=1;i<n;i++){
		cnt=cnt*b[i]/gys(cnt,b[i]);	
	}
	cout<<cnt;
	return 0;
}
